import React from 'react';
import { motion } from 'framer-motion';
import { FaGithub, FaExternalLinkAlt } from 'react-icons/fa';

const Projects = () => {
  const projects = [
    {
      title: 'E-Commerce Platform',
      description: 'A full-featured e-commerce platform built with React, Redux, and Node.js. Features include user authentication, product management, shopping cart, and payment integration.',
      image: '/project1.jpg',
      technologies: ['HTML','CSS','Java Script'],
      github: 'https://github.com/TechyAadi12/Code-Alpha',
      demo: 'https://ecommerce-demo.com',
      featured: true
    },
    {
      title: 'Task Management App',
      description: 'A collaborative task management application with real-time updates, drag-and-drop functionality, and team collaboration features.',
      image: '/project2.jpg',
      technologies: ['HTML','CSS','Java Script'],
      github: 'https://github.com/TechyAadi12/Code-Alpha',
      demo: 'https://task-manager-demo.com',
      featured: true
    },
    {
      title: 'Portfolio Website',
      description: 'A modern, responsive portfolio website built with React and Tailwind CSS. Features smooth animations and dark mode support.',
      image: '/project3.jpg',
      technologies: ['HTML','CSS','Java Script'],
      github: 'https://github.com/TechyAadi12/Code-Alpha',
      demo: 'https://portfolio-demo.com',
      featured: true
    },
    {
      title: 'Calculator',
      description: 'A modern, responsive portfolio website built with React and Tailwind CSS. Features smooth animations and dark mode support.',
      image: '/project3.jpg',
      technologies: ['HTML','CSS','Java Script'],
      github: 'https://github.com/TechyAadi12/Code-Alpha',
      demo: 'https://portfolio-demo.com',
      featured: true
    },
    {
      title: 'Music Player',
      description: 'A modern, responsive portfolio website built with React and Tailwind CSS. Features smooth animations and dark mode support.',
      image: '/project3.jpg',
      technologies: ['HTML','CSS','Java Script'],
      github: 'https://github.com/TechyAadi12/Code-Alpha',
      demo: 'https://portfolio-demo.com',
      featured: true
    },
    {
      title: 'Image Gallary',
      description: 'A modern, responsive portfolio website built with React and Tailwind CSS. Features smooth animations and dark mode support.',
      image: '/project3.jpg',
      technologies: ['HTML','CSS','Java Script'],
      github: 'https://github.com/TechyAadi12/Code-Alpha',
      demo: 'https://portfolio-demo.com',
      featured: true
    }
  ];

  return (
    <section id="projects" className="section">
      <div className="container">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          viewport={{ once: true }}
          className="text-center mb-16"
        >
          <h2 className="heading">Featured Projects</h2>
          <p className="subheading">Some things I've built</p>
        </motion.div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {projects.map((project, index) => (
            <motion.div
              key={project.title}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              viewport={{ once: true }}
              className="bg-tertiary rounded-lg overflow-hidden group"
            >
              {/* Project Image */}
              <div className="relative h-48 overflow-hidden">
                <div className="absolute inset-0 bg-secondary opacity-20 group-hover:opacity-30 transition-opacity"></div>
                <div className="w-full h-full bg-primary flex items-center justify-center">
                  <span className="text-2xl text-secondary">{project.title}</span>
                </div>
              </div>

              {/* Project Content */}
              <div className="p-6">
                <h3 className="text-xl font-semibold mb-2">{project.title}</h3>
                <p className="text-textSecondary mb-4">{project.description}</p>
                
                {/* Technologies */}
                <div className="flex flex-wrap gap-2 mb-4">
                  {project.technologies.map((tech) => (
                    <span
                      key={tech}
                      className="px-3 py-1 bg-primary text-secondary rounded-full text-sm"
                    >
                      {tech}
                    </span>
                  ))}
                </div>

                {/* Project Links */}
                <div className="flex gap-4">
                  <a
                    href={project.github}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="flex items-center gap-2 text-textSecondary hover:text-secondary transition-colors"
                  >
                    <FaGithub />
                    <span>Code</span>
                  </a>
                  <a
                    href={project.demo}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="flex items-center gap-2 text-textSecondary hover:text-secondary transition-colors"
                  >
                    <FaExternalLinkAlt />
                    <span>Live Demo</span>
                  </a>
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Projects;
